mapper.select:
		/* UserQuiescenceMapper.xml - getQuiescenceUserCnt */
        SELECT COUNT(1)
          FROM TADMIN_MST_UR
         WHERE DELYN = 'N'
           AND LASTLOGINDATE < #{expireMaxDate}

mapper.update:
/* UserQuiescenceMapper.xml - updateQuiescenceUser */
UPDATE TADMIN_MST_UR
   SET QUIESCENCEYN = 'Y'
    ,  UPDATEDATE = #{sysdate}
    ,  UPDATEURKEY = #{updateUrkey}
 WHERE DELYN = 'N'
   AND LASTLOGINDATE < #{expireDate}
